import React from 'react';
import { Box, Typography, Button, useTheme } from '@mui/material';
import { motion } from 'framer-motion';
import { useNavigate } from 'react-router-dom';

const Home: React.FC = () => {
  const theme = useTheme();
  const navigate = useNavigate();

  return (
    <Box
      sx={{
        minHeight: '100vh',
        display: 'flex',
        flexDirection: 'column',
        justifyContent: 'center',
        alignItems: 'center',
        bgcolor: 'background.default',
        textAlign: 'center',
        p: 4,
      }}
    >
      <motion.div
        initial={{ opacity: 0, y: 50 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.5 }}
      >
        <Typography variant="h2" sx={{ fontWeight: 'bold', mb: 3, color: 'text.primary' }}>
          Welcome to HunterBot
        </Typography>
        <Typography variant="h5" sx={{ mb: 4, color: 'text.secondary' }}>
          Find your dream job or hire top talent with our AI-powered platform.
        </Typography>
        <Box sx={{ display: 'flex', gap: 2 }}>
          <Button
            variant="contained"
            onClick={() => navigate('/jobs')}
            sx={{ borderRadius: 2, px: 4, py: 1.5, bgcolor: 'primary.main' }}
          >
            Browse Jobs
          </Button>
          <Button
            variant="outlined"
            onClick={() => navigate('/login')}
            sx={{ borderRadius: 2, px: 4, py: 1.5 }}
          >
            Login
          </Button>
        </Box>
      </motion.div>
    </Box>
  );
};

export default Home;
